diff --git a/app/src/server/webhook/github-commit-processor.ts b/app/src/server/webhook/github-commit-processor.ts
new file mode 100644
index 0000000..3687e6e
--- /dev/null
+++ b/app/src/server/webhook/github-commit-processor.ts
@@ -0,0 +1,229 @@
+import { randomUUID } from "node:crypto";
+import { RecordId } from "surrealdb";
+import { extractStructuredGraph } from "../extraction/extract-graph";
+import { persistExtractionOutput } from "../extraction/persist-extraction";
+import { loadWorkspaceGraphContext } from "../extraction/context-loaders";
+import { loadWorkspaceProjects } from "../workspace/workspace-scope";
+import { findWorkspacePersonByName } from "../extraction/person";
+import { createEmbedding } from "../extraction/embedding-writeback";
+import { createObservation } from "../observation/queries";
+import { elapsedMs, logError, logInfo } from "../http/observability";
+import type { SourceRecord } from "../extraction/types";
+import type { CommitInput, ProcessCommitResult, ProcessWebhookInput, ProcessWebhookResult } from "./types";
+
+export async function processGitCommits(input: ProcessWebhookInput): Promise<ProcessWebhookResult> {
+  const startedAt = performance.now();
+  const workspaceId = input.workspaceRecord.id as string;
+
+  logInfo("webhook.commits.started", "Processing commits", {
+    workspaceId,
+    repository: input.event.repository.full_name,
+    commitCount: input.event.commits.length,
+  });
+
+  const projects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
+  const projectNames = projects.map((p) => p.name);
+
+  const [workspaceRows] = await input.surreal
+    .query<[Array<{ name: string }>]>("SELECT name FROM $workspace LIMIT 1;", {
+      workspace: input.workspaceRecord,
+    })
+    .collect<[Array<{ name: string }>]>();
+  const workspaceName = workspaceRows[0]?.name;
+
+  const result: ProcessWebhookResult = {
+    commitsProcessed: 0,
+    commitsSkipped: 0,
+    totalEntities: 0,
+    totalRelationships: 0,
+    autoLinkedDecisions: [],
+    observationsCreated: [],
+  };
+
+  for (const rawCommit of input.event.commits) {
+    const commit: CommitInput = {
+      sha: rawCommit.id,
+      message: rawCommit.message,
+      authoredAt: rawCommit.timestamp,
+      authorName: rawCommit.author.name,
+      authorEmail: rawCommit.author.email,
+      authorUsername: rawCommit.author.username,
+      url: rawCommit.url,
+      repository: input.event.repository.full_name,
+    };
+
+    try {
+      const commitResult = await processCommit({
+        surreal: input.surreal,
+        extractionModel: input.extractionModel,
+        embeddingModel: input.embeddingModel,
+        embeddingDimension: input.embeddingDimension,
+        extractionStoreThreshold: input.extractionStoreThreshold,
+        extractionModelId: input.extractionModelId,
+        workspaceRecord: input.workspaceRecord,
+        commit,
+        workspaceName,
+        projectNames,
+        autoLinkThreshold: input.autoLinkThreshold,
+        now: new Date(),
+      });
+
+      result.commitsProcessed += 1;
+      result.totalEntities += commitResult.entities.length;
+      result.totalRelationships += commitResult.relationships.length;
+      result.autoLinkedDecisions.push(...commitResult.autoLinkedDecisions);
+      result.observationsCreated.push(...commitResult.observationsCreated);
+    } catch (error) {
+      logError("webhook.commit.failed", "Failed to process commit", error, {
+        workspaceId,
+        sha: commit.sha,
+      });
+      result.commitsSkipped += 1;
+    }
+  }
+
+  logInfo("webhook.commits.completed", "Finished processing commits", {
+    workspaceId,
+    ...result,
+    durationMs: elapsedMs(startedAt),
+  });
+
+  return result;
+}
+
+async function processCommit(input: {
+  surreal: typeof import("surrealdb").Surreal.prototype;
+  extractionModel: unknown;
+  embeddingModel: unknown;
+  embeddingDimension: number;
+  extractionStoreThreshold: number;
+  extractionModelId: string;
+  workspaceRecord: RecordId<"workspace", string>;
+  commit: CommitInput;
+  workspaceName?: string;
+  projectNames?: string[];
+  autoLinkThreshold: number;
+  now: Date;
+}): Promise<ProcessCommitResult> {
+  const commitRecordId = randomUUID();
+  const commitRecord = new RecordId("git_commit", commitRecordId);
+
+  // Resolve author
+  const authorRecord = await findWorkspacePersonByName({
+    surreal: input.surreal,
+    workspaceRecord: input.workspaceRecord,
+    personName: input.commit.authorName,
+  });
+
+  // Create embedding for commit message
+  const embedding = await createEmbedding(
+    input.embeddingModel,
+    input.embeddingDimension,
+    input.commit.message,
+  );
+
+  // Persist git_commit record
+  await input.surreal.create(commitRecord).content({
+    sha: input.commit.sha,
+    repository: input.commit.repository,
+    message: input.commit.message,
+    authored_at: new Date(input.commit.authoredAt),
+    ...(authorRecord ? { author: authorRecord } : {}),
+    url: input.commit.url,
+    workspace: input.workspaceRecord,
+    ...(embedding ? { embedding } : {}),
+    created_at: input.now,
+  });
+
+  logInfo("webhook.commit.created", "Created git_commit record", {
+    sha: input.commit.sha,
+    commitRecordId,
+  });
+
+  // Load workspace graph context for extraction
+  const graphContext = await loadWorkspaceGraphContext(
+    input.surreal,
+    input.workspaceRecord,
+    60,
+  );
+
+  // Run extraction on commit message
+  const extractionOutput = await extractStructuredGraph({
+    extractionModel: input.extractionModel,
+    conversationHistory: [],
+    graphContext,
+    sourceText: input.commit.message,
+    onboarding: false,
+    workspaceName: input.workspaceName,
+    projectNames: input.projectNames,
+  });
+
+  // Persist extracted entities and relationships
+  const persisted = await persistExtractionOutput({
+    surreal: input.surreal,
+    extractionModel: input.extractionModel,
+    embeddingModel: input.embeddingModel,
+    embeddingDimension: input.embeddingDimension,
+    extractionModelId: input.extractionModelId,
+    extractionStoreThreshold: input.extractionStoreThreshold,
+    workspaceRecord: input.workspaceRecord,
+    sourceRecord: commitRecord as SourceRecord,
+    sourceKind: "git_commit",
+    sourceLabel: `commit ${input.commit.sha.slice(0, 8)}`,
+    promptText: input.commit.message,
+    output: extractionOutput,
+    sourceCommitRecord: commitRecord,
+    now: input.now,
+  });
+
+  // Auto-link decisions based on confidence
+  const autoLinkedDecisions: string[] = [];
+  const observationsCreated: string[] = [];
+
+  for (const entity of persisted.entities) {
+    if (entity.kind !== "decision") continue;
+
+    const decisionRecord = new RecordId("decision", entity.id);
+
+    if (entity.confidence >= input.autoLinkThreshold) {
+      await input.surreal
+        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
+          commit_sha: input.commit.sha,
+          linked_at: input.now,
+        })
+        .output("after");
+
+      autoLinkedDecisions.push(entity.id);
+      logInfo("webhook.commit.autolinked", "Auto-linked decision to commit", {
+        decisionId: entity.id,
+        sha: input.commit.sha,
+        confidence: entity.confidence,
+      });
+    } else {
+      const observation = await createObservation({
+        surreal: input.surreal,
+        workspaceRecord: input.workspaceRecord,
+        text: `Commit ${input.commit.sha.slice(0, 8)} may implement decision "${entity.text}" (confidence: ${(entity.confidence * 100).toFixed(0)}%). Please confirm.`,
+        severity: "info",
+        sourceAgent: "git_webhook",
+        now: input.now,
+        relatedRecord: decisionRecord,
+      });
+
+      observationsCreated.push(observation.id as string);
+      logInfo("webhook.commit.observation", "Created confirmation observation", {
+        decisionId: entity.id,
+        sha: input.commit.sha,
+        confidence: entity.confidence,
+      });
+    }
+  }
+
+  return {
+    commitRecord,
+    entities: persisted.entities,
+    relationships: persisted.relationships,
+    autoLinkedDecisions,
+    observationsCreated,
+  };
+}
diff --git a/app/src/server/webhook/github-webhook-route.ts b/app/src/server/webhook/github-webhook-route.ts
new file mode 100644
index 0000000..0e55785
--- /dev/null
+++ b/app/src/server/webhook/github-webhook-route.ts
@@ -0,0 +1,125 @@
+import type { ServerDependencies } from "../runtime/types";
+import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
+import { jsonError, jsonResponse } from "../http/response";
+import { logError, logInfo } from "../http/observability";
+import { processGitCommits } from "./github-commit-processor";
+import type { GitHubPushEvent } from "./types";
+
+export function createGitHubWebhookHandler(
+  deps: ServerDependencies,
+): (workspaceId: string, request: Request) => Promise<Response> {
+  return (workspaceId: string, request: Request) =>
+    handleGitHubWebhook(deps, workspaceId, request);
+}
+
+async function handleGitHubWebhook(
+  deps: ServerDependencies,
+  workspaceId: string,
+  request: Request,
+): Promise<Response> {
+  const eventType = request.headers.get("x-github-event");
+  if (!eventType) {
+    return jsonError("missing x-github-event header", 400);
+  }
+
+  if (eventType !== "push") {
+    logInfo("webhook.github.skipped", "Non-push event ignored", { eventType });
+    return jsonResponse({ accepted: true, reason: "event type not processed" }, 200);
+  }
+
+  const rawBody = await request.text();
+
+  if (deps.config.githubWebhookSecret) {
+    const signature = request.headers.get("x-hub-signature-256");
+    if (!signature) {
+      return jsonError("missing x-hub-signature-256 header", 401);
+    }
+
+    const valid = await verifyGitHubSignature(deps.config.githubWebhookSecret, rawBody, signature);
+    if (!valid) {
+      return jsonError("invalid signature", 401);
+    }
+  }
+
+  const event = JSON.parse(rawBody) as GitHubPushEvent;
+
+  const expectedRef = `refs/heads/${event.repository.default_branch}`;
+  if (event.ref !== expectedRef) {
+    logInfo("webhook.github.skipped", "Non-default branch push ignored", {
+      ref: event.ref,
+      defaultBranch: event.repository.default_branch,
+    });
+    return jsonResponse({ accepted: true, reason: "non-default branch" }, 200);
+  }
+
+  if (event.commits.length === 0) {
+    return jsonResponse({ accepted: true, reason: "no commits" }, 200);
+  }
+
+  let workspaceRecord;
+  try {
+    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
+  } catch {
+    return jsonError("workspace not found", 404);
+  }
+
+  logInfo("webhook.github.accepted", "Processing push event", {
+    workspaceId,
+    repository: event.repository.full_name,
+    commitCount: event.commits.length,
+  });
+
+  // Fire-and-forget: process commits asynchronously so we return 200 within GitHub's timeout
+  void processGitCommits({
+    surreal: deps.surreal,
+    extractionModel: deps.extractionModel,
+    embeddingModel: deps.embeddingModel,
+    embeddingDimension: deps.config.embeddingDimension,
+    extractionStoreThreshold: deps.config.extractionStoreThreshold,
+    extractionModelId: deps.config.extractionModelId,
+    workspaceRecord,
+    event,
+    autoLinkThreshold: 0.85,
+  }).catch((error) => {
+    logError("webhook.github.processing_failed", "Commit processing failed", error, {
+      workspaceId,
+      repository: event.repository.full_name,
+    });
+  });
+
+  return jsonResponse({
+    accepted: true,
+    commitsQueued: event.commits.length,
+  }, 202);
+}
+
+async function verifyGitHubSignature(
+  secret: string,
+  payload: string,
+  signature: string,
+): Promise<boolean> {
+  const encoder = new TextEncoder();
+  const key = await crypto.subtle.importKey(
+    "raw",
+    encoder.encode(secret),
+    { name: "HMAC", hash: "SHA-256" },
+    false,
+    ["sign"],
+  );
+  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(payload));
+  const computed = `sha256=${Buffer.from(sig).toString("hex")}`;
+
+  if (computed.length !== signature.length) {
+    return false;
+  }
+
+  // Constant-time comparison
+  const a = encoder.encode(computed);
+  const b = encoder.encode(signature);
+  if (a.length !== b.length) return false;
+  let diff = 0;
+  for (let i = 0; i < a.length; i++) {
+    diff |= a[i] ^ b[i];
+  }
+  return diff === 0;
+}
